import * as React from "react";
import type { HeadFC, PageProps } from "gatsby";
import styled from "styled-components";
import "../styles/global.css";

const StyledMain = styled.main`
  background-color: #0f0f0f;
  min-height: 100vh;
  gap: 20px;
  display: flex;
  flex-direction: column;
  padding: 60px 10%;
  * {
    margin: 0;
    font-family: "Montserrat";
    color: white;
  }
  h1 {
    font-size: 35px;
  }
  h2 {
    font-size: 20px;
  }
`;

const PrivacyPolicyPage: React.FC<PageProps> = () => {
  return (
    <StyledMain>
      <h1>Privacy Policy</h1>
      <a href="/">Back to Home</a>

      <p>
        This Privacy Policy describes how I handle the personal information of
        users of my application, available on Google Play, and my website. By
        using my application or website, you agree to the terms outlined in this
        policy.
      </p>

      <h2>1. Information about the Application</h2>
      <p>
        My application is available for free on Google Play. It does not collect
        any personal data from users. No personal information, such as name,
        email address, or phone number, is required to use the application. The
        application also does not transmit any data to third parties.
      </p>

      <h2>2. Scope of Data Collection</h2>
      <p>
        I do not collect, store, or process any personal data from users of my
        application. The application does not use any tracking mechanisms or
        analytics tools to monitor user behavior.
      </p>

      <h2>3. Cookies and Similar Technologies</h2>
      <p>
        My website may use cookies and similar technologies to enhance user
        experience and improve the functionality of my services. Cookies are
        small text files stored on your device when you visit my website. They
        help me understand how you interact with my content, which pages are
        most visited, and how I can make my website more useful.
      </p>

      <p>
        I do not use cookies to collect personal information. You can control
        and manage cookies through your browser settings. Please note that
        disabling cookies may affect the performance and functionality of my
        website.
      </p>

      <h2>4. Security of Data</h2>
      <p>
        I am committed to ensuring the security of any information you provide
        to me. Although my application does not collect personal data, my
        website may use secure protocols to protect data transmission over the
        internet. However, no method of electronic transmission or storage is
        100% secure, and I cannot guarantee absolute security.
      </p>

      <h2>5. User Rights</h2>
      <p>
        As my application does not collect personal data, users do not need to
        take any specific actions regarding their data. However, should you have
        any questions about your privacy rights or concerns about how I handle
        data, please feel free to contact me.
      </p>

      <h2>6. Third-Party Links</h2>
      <p>
        My application or website may contain links to third-party websites. I
        am not responsible for the privacy practices or content of these
        third-party websites. I encourage you to read the privacy policies of
        any website you visit.
      </p>

      <h2>7. Children's Privacy</h2>
      <p>
        My application and website are not intended for use by children under
        the age of 13. I do not knowingly collect or solicit personal
        information from anyone under the age of 13. If you are a parent or
        guardian and believe your child has provided me with personal
        information, please contact me immediately, and I will take appropriate
        steps to remove that information.
      </p>

      <h2>8. Changes to the Privacy Policy</h2>
      <p>
        I reserve the right to modify this Privacy Policy at any time. Any
        changes will be posted on this page and will become effective
        immediately upon posting. I encourage you to review this Privacy Policy
        periodically to stay informed about how I protect your information.
      </p>

      <h2>9. Contact Information</h2>
      <p>
        If you have any questions or concerns about my Privacy Policy or the
        practices of my application or website, please contact me at:{" "}
        <a href="mailto:mateusz.zebala.pl@gmail.com">
          mateusz.zebala.pl@gmail.com
        </a>
        .
      </p>

      <p>Last updated: September 8, 2024</p>
    </StyledMain>
  );
};

export default PrivacyPolicyPage;

export const Head: HeadFC = () => (
  <>
    <title>Mateusz Zębala - Privacy Policy</title>
    <meta
      name="description"
      content="Junior Software Developer, Poland, Cracow, I am an independent, ambitious, and determinedindividual committed to achieving set goals. I havebeen involved in programming for about 5 years. Ipossess a considerable amount of knowledge and astrong desire to continually acquire new skills. I amopen to new challenges and prepared to dedicate timeand energy to effectively fulfill assignedresponsibilities. I have been tutoring programming forover a year, teaching mainly JavaScript and Python."
    />
    <meta
      name="keywords"
      content="Python, JavaScript, TypeScript, React, Redux, Django, Flask, Git, Github, MongoDB, MySQL, Docker"
    />
    <meta name="author" content="Mateusz Zębala" />
  </>
);
